noncompliant:
// Noncompliant: Converting function pointer to different type
int intFunction(int a) {
  return a * 2;
}

void example() {
  // Unsafe conversion to different function signature
  float (*floatPtr)(float) = (float (*)(float))&intFunction;
}

compliant:
// Compliant: Using function pointer with correct type
int intFunction(int a) {
  return a * 2;
}

float floatFunction(float a) {
  return a * 2.0f;
}

void example() {
  // Correct: Using function pointer with matching signature
  int (*intPtr)(int) = &intFunction;
  float (*floatPtr)(float) = &floatFunction;

  int result1 = intPtr(5);
  float result2 = floatPtr(5.0f);
}
